/* ---------------------------------------------------------------------
 * Accessibility: the spinner must announce "loading" to screen readers
 *
 * Sighted users see a spinning icon while a search fetch is in flight, but
 * a plain <div> spinner is invisible to assistive tech — the previous
 * results simply vanish with no explanation, which fails WCAG 4.1.3 (Status
 * Messages). The spinner wrapper is therefore marked role="status" (an
 * implicit polite live region) carrying an aria-label describing the state,
 * so AT announces it when it appears. The icon itself stays decorative (no
 * text content) so it is not read aloud separately on top of the label.
 * The visual styling is left untouched — the attributes are purely
 * additive.
 * ------------------------------------------------------------------ */
describe('spinner is announced to assistive tech (WCAG 4.1.3)', () => {
  it('marks the spinner wrapper role="status" (an implicit polite live region)', async () => {
    const { release } = stubHeldSearch('slow-query');
    const { results } = setup({ hash: toSearchHash('slow-query', '') });
    await flush(); // settle the initial browse render

    navigate(toSearchHash('slow-query', ''));
    await flush();

    const spinner = results.querySelector('.search-spinner');
    expect(
      spinner,
      'a .search-spinner element must exist during an in-flight search',
    ).toBeTruthy();
    // role="status" makes the div an implicit aria-live="polite" region, so its
    // appearance is announced to screen readers without stealing focus
    // (WCAG 4.1.3 Status Messages). A bare <div> with no role is silent.
    expect(spinner!.getAttribute('role')).toBe('status');

    release();
    await flush();
  });

  it('sets aria-label="Loading search results" so the announcement is meaningful', async () => {
    const { release } = stubHeldSearch('slow-query');
    const { results } = setup({ hash: toSearchHash('slow-query', '') });
    await flush();

    navigate(toSearchHash('slow-query', ''));
    await flush();

    const spinner = results.querySelector('.search-spinner');
    expect(
      spinner,
      'a .search-spinner element must exist during an in-flight search',
    ).toBeTruthy();
    // The wrapper has no text content of its own, so its accessible name must
    // come from aria-label — otherwise AT would announce nothing useful when
    // the (implicit) live region updates.
    expect(spinner!.getAttribute('aria-label')).toBe('Loading search results');

    release();
    await flush();
  });

  it('keeps the spinner icon decorative (no text content) so AT does not read it', async () => {
    const { release } = stubHeldSearch('slow-query');
    const { results } = setup({ hash: toSearchHash('slow-query', '') });
    await flush();

    navigate(toSearchHash('slow-query', ''));
    await flush();

    const spinner = results.querySelector('.search-spinner');
    expect(
      spinner,
      'a .search-spinner element must exist during an in-flight search',
    ).toBeTruthy();
    const icon = spinner!.querySelector('.bi-arrow-repeat.spinning');
    expect(icon, 'the spinner must contain its spinning icon').toBeTruthy();
    // The icon carries no text — so it is not announced by AT on top of the
    // wrapper's aria-label (decorative-icons contract).
    expect((icon!.textContent ?? '').trim()).toBe('');

    release();
    await flush();
  });

  it('does not change the visual styling (className and icon classes are preserved)', async () => {
    const { release } = stubHeldSearch('slow-query');
    const { results } = setup({ hash: toSearchHash('slow-query', '') });
    await flush();

    navigate(toSearchHash('slow-query', ''));
    await flush();

    const spinner = results.querySelector('.search-spinner');
    expect(
      spinner,
      'a .search-spinner element must exist during an in-flight search',
    ).toBeTruthy();
    // The accessibility attributes are additive; the visual class hooks that
    // app.css keys off (.search-spinner wrapper, .bi bi-arrow-repeat spinning
    // icon) must be exactly what they were before the a11y change.
    expect(spinner!.className).toBe('search-spinner');
    const icon = spinner!.querySelector('i');
    expect(icon, 'the spinner icon <i> must still be present').toBeTruthy();
    expect(icon!.className).toBe('bi bi-arrow-repeat spinning');

    release();
    await flush();
  });
});

