+  /* ---------------------------------------------------------------------
+   * Accessibility: the spinner wrapper must announce "loading" to screen
+   * readers (WCAG 4.1.3 Status Messages)
+   *
+   * While a search fetch is in flight the previous results vanish and a
+   * sighted user sees a spinning glyph, but a plain <div> wrapper is silent
+   * to assistive tech — no status message is announced, violating WCAG 4.1.3.
+   * The wrapper is therefore marked `role="status"` (an implicit polite live
+   * region) and given an `aria-label` so its appearance is announced with a
+   * meaningful message. The visual styling is untouched; the attributes are
+   * purely additive.
+   *
+   * NOTE: this is distinct from the `aria-hidden="true"` test on the spinner
+   * *icon* further below (WCAG 1.3.1 decorative glyphs) — that hides the
+   * glyph from AT; these tests ensure the wrapper *is* announced as a status
+   * region. Both are required: the wrapper announces while the glyph stays
+   * quiet.
+   * ------------------------------------------------------------------ */
+  describe('spinner wrapper announces loading to assistive tech (WCAG 4.1.3)', () => {
+    it('marks the spinner wrapper role="status" so its appearance is announced', async () => {
+      const { release } = stubHeldSearch('slow-query');
+      const { results } = setup({ hash: toSearchHash('slow-query', '') });
+      await flush(); // settle the initial browse render
+
+      navigate(toSearchHash('slow-query', ''));
+      await flush();
+
+      const spinner = results.querySelector('.search-spinner');
+      expect(
+        spinner,
+        'a .search-spinner element must exist during an in-flight search',
+      ).toBeTruthy();
+      // role="status" maps to an implicit aria-live="polite" region: AT announces
+      // the element when it appears, without stealing focus. A bare <div> with no
+      // role is silent, so the loading state would never be announced.
+      expect(spinner!.getAttribute('role')).toBe('status');
+
+      release();
+      await flush();
+    });
+
+    it('sets aria-label="Loading search results" for a meaningful announcement', async () => {
+      const { release } = stubHeldSearch('slow-query');
+      const { results } = setup({ hash: toSearchHash('slow-query', '') });
+      await flush(); // settle the initial browse render
+
+      navigate(toSearchHash('slow-query', ''));
+      await flush();
+
+      const spinner = results.querySelector('.search-spinner');
+      expect(
+        spinner,
+        'a .search-spinner element must exist during an in-flight search',
+      ).toBeTruthy();
+      // The wrapper has no text content of its own (its only child is the
+      // decorative icon), so its accessible name must come from aria-label —
+      // otherwise the implicit live region would announce nothing useful when
+      // the spinner appears.
+      expect(spinner!.getAttribute('aria-label')).toBe('Loading search results');
+
+      release();
+      await flush();
+    });
+  });
+
